    83→export const getCleanedImageUrl = (url: string | undefined): string | undefined => {
    84→  if (!url) return undefined;
    85→  
    86→  let cleanedUrl = url.trim();
    87→  
    88→  if (cleanedUrl.startsWith('imageUrl:')) {
    89→    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
    90→  }
    91→  
    92→  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
    93→    return cleanedUrl;
    94→  }
    95→  
    96→  return undefined;
    97→};
